async def upsert_session(
    db: aiosqlite.Connection,
    *,
    session_id: str,
    pid: int = 0,
    cwd: str = "",
    entrypoint: str = "cli",
    started_at: int = 0,
    last_event: str | None = None,
    last_tool: str | None = None,
    last_event_at: float | None = None,
    branch: str = "",
    source_system: str = "",
) -> None:
    """Insert or update a session row. On conflict, update event fields."""
    now = time.time()
    await db.execute(
        """
        INSERT INTO claude_sessions
            (session_id, pid, cwd, entrypoint, started_at,
             last_event, last_tool, last_event_at, discovered_at, branch,
             source_system)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        ON CONFLICT(session_id) DO UPDATE SET
            last_event = COALESCE(excluded.last_event, last_event),
            last_tool = COALESCE(excluded.last_tool, last_tool),
            last_event_at = COALESCE(excluded.last_event_at, last_event_at),
            cwd = CASE WHEN excluded.cwd != '' THEN excluded.cwd ELSE cwd END,
            pid = CASE WHEN excluded.pid != 0 THEN excluded.pid ELSE pid END,
            source_system = CASE
                WHEN excluded.source_system != '' THEN excluded.source_system
                ELSE source_system
            END
        """,
        (
            session_id,
            pid,
            cwd,
            entrypoint,
            started_at,
            last_event,
            last_tool,
            last_event_at,
            now,
            branch,
            source_system,
        ),
    )
    await db.commit()


async def end_session(
    db: aiosqlite.Connection,
    *,
    session_id: str,
    ended_at: float | None = None,
) -> None:
    """Mark a session as ended."""
    ts = time.time() if ended_at is None else ended_at
    await db.execute(
        "UPDATE claude_sessions SET ended_at = ? WHERE session_id = ?",
        (ts, session_id),
    )
