async def get_all_sessions(
    db: aiosqlite.Connection,
    *,
    active: bool | None = None,
) -> list[dict]:
    """Return all sessions, optionally filtered by active status."""
    query = "SELECT * FROM claude_sessions"
    params: list[object] = []

    if active is True:
        query += " WHERE pid_alive = 1 AND ended_at IS NULL"
    elif active is False:
        query += " WHERE pid_alive = 0 OR ended_at IS NOT NULL"

    query += " ORDER BY started_at DESC"
    cursor = await db.execute(query, params)
    rows = await cursor.fetchall()
    return [dict(row) for row in rows]


