async def clear_session(
    db: aiosqlite.Connection,
    *,
    session_id: str,
    cleared_at: float | None = None,
) -> None:
    """Reset a session's current state as if freshly connected.

    Clears last_event/last_tool/last_event_at on the session and ends
    all active agents. Historical events remain intact.
    """
    ts = time.time() if cleared_at is None else cleared_at
    await db.execute(
        """
        UPDATE claude_sessions
        SET last_event = NULL, last_tool = NULL, last_event_at = NULL
        WHERE session_id = ?
        """,
        (session_id,),
    )
    await db.execute(
        """
        UPDATE claude_agents
        SET ended_at = ?
        WHERE session_id = ? AND ended_at IS NULL
        """,
        (ts, session_id),
    )
    await db.commit()


